@import "tailwindcss";

:root {
  --bg: #0b0d0f;
  --bg-1: #0f1216;
  --bg-2: #14181d;
  --bg-3: #1a1f25;
  --border: #1f242a;
  --border-strong: #2a3038;
  --fg: #e8e8e8;
  --fg-1: #c9ccd1;
  --fg-2: #7a8290;
  --fg-3: #454c56;
  --accent: #7dd3a0;
  --accent-dim: #7dd3a022;
  --accent-fg: #0b0d0f;
  --blue: #7aa7e8;
  --amber: #e8b87a;
  --red: #e87a7a;
  --purple: #b8a1e8;
  --teal: #7ad3c9;
  --font-ui: "Inter", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, "SF Mono", Menlo, monospace;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html, body {
  background: var(--bg);
  color: var(--fg);
  font-family: var(--font-ui);
  height: 100%;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

input, textarea, button, select {
  font-family: inherit;
}

@keyframes aurora-1 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(30px, -20px) scale(1.1); }
  66% { transform: translate(-20px, 10px) scale(0.9); }
}

@keyframes aurora-2 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(-40px, 20px) scale(1.15); }
  66% { transform: translate(20px, -30px) scale(0.85); }
}

@keyframes aurora-3 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  50% { transform: translate(20px, 30px) scale(1.2); }
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.3; }
}

@keyframes spin-slow {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.fade-in {
  animation: fadeIn 0.3s ease forwards;
}

.aurora-blob-1 {
  animation: aurora-1 8s ease-in-out infinite;
}

.aurora-blob-2 {
  animation: aurora-2 10s ease-in-out infinite;
}

.aurora-blob-3 {
  animation: aurora-3 12s ease-in-out infinite;
}

export interface User {
  id: string;
  email: string;
}

export interface AuthResponse {
  access_token: string;
  token_type: string;
  user: User;
}

export interface Campaign {
  id: string;
  type: "job_outreach" | "b2b" | "investor_outreach" | "custom";
  status: "draft" | "processing" | "ready" | "completed";
  config_json?: Record<string, unknown>;
  created_at: string;
}

export interface CampaignListResponse {
  campaigns: Campaign[];
  total: number;
}

export interface CampaignCreateResponse {
  campaign_id: string;
  session_id: string;
  status: string;
  first_message: string;
}

export interface CampaignStats {
  total_contacts: number;
  total_drafts: number;
  approved: number;
  queued: number;
  sent: number;
  opened: number;
  replied: number;
  bounced: number;
  failed: number;
}

export interface ChatMessage {
  role: "assistant" | "user";
  content: string;
}

export interface ChatHistoryResponse {
  session_id: string;
  status: string;
  chat_history: ChatMessage[];
  extracted_params: Record<string, unknown>;
}

export interface Contact {
  company: string;
  person_name: string;
  email: string;
  title: string;
  source: string;
  bounce_risk: boolean;
}

export interface OutreachDraft {
  id: string;
  contact: Contact;
  subject: string;
  body: string;
  draft_status: "pending" | "approved" | "rejected";
  status: "draft" | "queued" | "sent" | "failed";
}

export interface OutreachListResponse {
  outreaches: OutreachDraft[];
  total: number;
  page: number;
  limit: number;
}

export interface EmailJob {
  id: string;
  contact_email: string;
  subject: string;
  status: "pending" | "queued" | "sent" | "failed";
  sent_at?: string;
}

export interface EmailJobsResponse {
  jobs: EmailJob[];
  total: number;
}

export interface EnqueueResponse {
  queued: number;
  skipped_bounced: number;
  message: string;
}

"use client";

import React from "react";

type BadgeVariant = "success" | "warning" | "error" | "info" | "purple" | "teal" | "neutral";

interface BadgeProps {
  label: string;
  variant?: BadgeVariant;
}

const variantStyles: Record<BadgeVariant, React.CSSProperties> = {
  success: { background: "var(--accent-dim)", color: "var(--accent)", border: "1px solid var(--accent)33" },
  warning: { background: "#e8b87a22", color: "var(--amber)", border: "1px solid #e8b87a33" },
  error: { background: "#e87a7a22", color: "var(--red)", border: "1px solid #e87a7a33" },
  info: { background: "#7aa7e822", color: "var(--blue)", border: "1px solid #7aa7e833" },
  purple: { background: "#b8a1e822", color: "var(--purple)", border: "1px solid #b8a1e833" },
  teal: { background: "#7ad3c922", color: "var(--teal)", border: "1px solid #7ad3c933" },
  neutral: { background: "var(--bg-3)", color: "var(--fg-2)", border: "1px solid var(--border)" },
};

const statusToVariant: Record<string, BadgeVariant> = {
  draft: "neutral",
  processing: "warning",
  ready: "success",
  completed: "info",
  pending: "neutral",
  approved: "success",
  rejected: "error",
  queued: "warning",
  sent: "info",
  failed: "error",
  active: "success",
  b2b: "blue" as BadgeVariant,
  job_outreach: "teal",
  investor_outreach: "purple",
  custom: "neutral",
};

export function Badge({ label, variant }: BadgeProps) {
  const resolvedVariant = variant || statusToVariant[label.toLowerCase()] || "neutral";
  const style = variantStyles[resolvedVariant] || variantStyles.neutral;

  return (
    <span
      style={{
        ...style,
        fontSize: "11px",
        fontWeight: 500,
        padding: "2px 8px",
        borderRadius: "6px",
        display: "inline-block",
        textTransform: "capitalize",
        whiteSpace: "nowrap",
      }}
    >
      {label.replace(/_/g, " ")}
    </span>
  );
}

"use client";

import React from "react";

type ButtonVariant = "primary" | "secondary" | "ghost" | "danger";
type ButtonSize = "sm" | "md" | "lg";

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: ButtonVariant;
  size?: ButtonSize;
  loading?: boolean;
  children: React.ReactNode;
}

const variantStyles: Record<ButtonVariant, React.CSSProperties> = {
  primary: {
    background: "var(--accent)",
    color: "var(--accent-fg)",
    border: "1px solid var(--accent)",
    fontWeight: 600,
  },
  secondary: {
    background: "var(--bg-3)",
    color: "var(--fg)",
    border: "1px solid var(--border-strong)",
  },
  ghost: {
    background: "transparent",
    color: "var(--fg-2)",
    border: "1px solid transparent",
  },
  danger: {
    background: "#e87a7a22",
    color: "var(--red)",
    border: "1px solid #e87a7a44",
  },
};

const sizeStyles: Record<ButtonSize, React.CSSProperties> = {
  sm: { fontSize: "12px", padding: "4px 10px", borderRadius: "6px", height: "28px" },
  md: { fontSize: "13px", padding: "6px 14px", borderRadius: "8px", height: "34px" },
  lg: { fontSize: "14px", padding: "10px 20px", borderRadius: "10px", height: "42px" },
};

export function Button({
  variant = "secondary",
  size = "md",
  loading = false,
  children,
  disabled,
  style,
  ...props
}: ButtonProps) {
  return (
    <button
      disabled={disabled || loading}
      style={{
        ...variantStyles[variant],
        ...sizeStyles[size],
        display: "inline-flex",
        alignItems: "center",
        gap: "6px",
        cursor: disabled || loading ? "not-allowed" : "pointer",
        opacity: disabled || loading ? 0.6 : 1,
        transition: "opacity 0.15s, background 0.15s",
        fontFamily: "var(--font-ui)",
        outline: "none",
        whiteSpace: "nowrap",
        ...style,
      }}
      {...props}
    >
      {loading ? (
        <span
          style={{
            width: "12px",
            height: "12px",
            border: "2px solid currentColor",
            borderTopColor: "transparent",
            borderRadius: "50%",
            display: "inline-block",
            animation: "spin-slow 0.7s linear infinite",
          }}
        />
      ) : null}
      {children}
    </button>
  );
}

"use client";

import React from "react";

interface FieldProps {
  label?: string;
  hint?: string;
  error?: string;
  required?: boolean;
  children: React.ReactNode;
}

export function Field({ label, hint, error, required, children }: FieldProps) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "6px" }}>
      {label && (
        <label
          style={{
            fontSize: "12px",
            fontWeight: 500,
            color: "var(--fg-2)",
            textTransform: "uppercase",
            letterSpacing: "0.04em",
          }}
        >
          {label}
          {required && (
            <span style={{ color: "var(--accent)", marginLeft: "3px" }}>*</span>
          )}
        </label>
      )}
      {children}
      {hint && !error && (
        <span style={{ fontSize: "11px", color: "var(--fg-3)" }}>{hint}</span>
      )}
      {error && (
        <span style={{ fontSize: "11px", color: "var(--red)" }}>{error}</span>
      )}
    </div>
  );
}

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  fullWidth?: boolean;
}

export function Input({ fullWidth, style, ...props }: InputProps) {
  return (
    <input
      style={{
        background: "var(--bg-2)",
        border: "1px solid var(--border)",
        borderRadius: "8px",
        color: "var(--fg)",
        fontSize: "13px",
        padding: "8px 12px",
        height: "36px",
        width: fullWidth ? "100%" : undefined,
        outline: "none",
        transition: "border-color 0.15s",
        fontFamily: "var(--font-ui)",
        ...style,
      }}
      onFocus={(e) => {
        e.currentTarget.style.borderColor = "var(--border-strong)";
        props.onFocus?.(e);
      }}
      onBlur={(e) => {
        e.currentTarget.style.borderColor = "var(--border)";
        props.onBlur?.(e);
      }}
      {...props}
    />
  );
}

interface TextAreaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  fullWidth?: boolean;
}

export function TextArea({ fullWidth, style, ...props }: TextAreaProps) {
  return (
    <textarea
      style={{
        background: "var(--bg-2)",
        border: "1px solid var(--border)",
        borderRadius: "8px",
        color: "var(--fg)",
        fontSize: "13px",
        padding: "10px 12px",
        width: fullWidth ? "100%" : undefined,
        outline: "none",
        transition: "border-color 0.15s",
        fontFamily: "var(--font-ui)",
        resize: "vertical",
        lineHeight: 1.5,
        ...style,
      }}
      onFocus={(e) => {
        e.currentTarget.style.borderColor = "var(--border-strong)";
        props.onFocus?.(e);
      }}
      onBlur={(e) => {
        e.currentTarget.style.borderColor = "var(--border)";
        props.onBlur?.(e);
      }}
      {...props}
    />
  );
}

"use client";

import React, { useEffect, useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { Badge } from "@/components/ui/Badge";
import type { Campaign } from "@/types";

export function Sidebar() {
  const pathname = usePathname();
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);

  useEffect(() => {
    fetch("/api/v1/campaigns")
      .then((r) => r.json())
      .then((data) => setCampaigns(data.campaigns || []))
      .catch(() => {});
  }, []);

  return (
    <aside
      style={{
        width: "220px",
        minWidth: "220px",
        background: "var(--bg-1)",
        borderRight: "1px solid var(--border)",
        display: "flex",
        flexDirection: "column",
        height: "100vh",
        position: "sticky",
        top: 0,
      }}
    >
      {/* Logo */}
      <div
        style={{
          padding: "16px 16px 12px",
          borderBottom: "1px solid var(--border)",
          display: "flex",
          alignItems: "center",
          gap: "8px",
        }}
      >
        <div
          style={{
            width: "24px",
            height: "24px",
            background: "var(--accent)",
            borderRadius: "6px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--accent-fg)" strokeWidth="2.5">
            <path d="M22 2L11 13" strokeLinecap="round" strokeLinejoin="round" />
            <path d="M22 2L15 22l-4-9-9-4 20-7z" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </div>
        <span style={{ fontSize: "14px", fontWeight: 600, color: "var(--fg)" }}>Outreach</span>
      </div>

      {/* Nav */}
      <nav style={{ padding: "8px" }}>
        <NavItem href="/dashboard" label="Dashboard" active={pathname === "/dashboard"} icon="⊞" />
        <NavItem href="/campaign/new" label="New Campaign" active={pathname === "/campaign/new"} icon="+" />
      </nav>

      {/* Campaigns list */}
      <div style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
        <div
          style={{
            padding: "8px 16px 4px",
            fontSize: "10px",
            fontWeight: 600,
            color: "var(--fg-3)",
            textTransform: "uppercase",
            letterSpacing: "0.08em",
          }}
        >
          Campaigns
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "0 8px 8px" }}>
          {campaigns.map((c) => {
            const isActive = pathname.includes(`/campaign/${c.id}`);
            return (
              <Link
                key={c.id}
                href={`/campaign/${c.id}/dashboard`}
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: "3px",
                  padding: "7px 10px",
                  borderRadius: "7px",
                  background: isActive ? "var(--bg-3)" : "transparent",
                  marginBottom: "1px",
                  transition: "background 0.1s",
                  cursor: "pointer",
                }}
              >
                <span
                  style={{
                    fontSize: "12px",
                    color: isActive ? "var(--fg)" : "var(--fg-1)",
                    fontWeight: isActive ? 500 : 400,
                    overflow: "hidden",
                    textOverflow: "ellipsis",
                    whiteSpace: "nowrap",
                  }}
                >
                  {c.type.replace(/_/g, " ")}
                </span>
                <Badge label={c.status} />
              </Link>
            );
          })}
        </div>
      </div>

      {/* Bottom */}
      <div style={{ padding: "12px", borderTop: "1px solid var(--border)" }}>
        <button
          onClick={() => {
            localStorage.removeItem("outreach_token");
            window.location.href = "/auth";
          }}
          style={{
            background: "none",
            border: "none",
            color: "var(--fg-3)",
            fontSize: "12px",
            cursor: "pointer",
            padding: "4px 6px",
            borderRadius: "6px",
            width: "100%",
            textAlign: "left",
          }}
        >
          Sign out
        </button>
      </div>
    </aside>
  );
}

function NavItem({
  href,
  label,
  active,
  icon,
}: {
  href: string;
  label: string;
  active: boolean;
  icon: string;
}) {
  return (
    <Link
      href={href}
      style={{
        display: "flex",
        alignItems: "center",
        gap: "8px",
        padding: "6px 10px",
        borderRadius: "7px",
        background: active ? "var(--bg-3)" : "transparent",
        color: active ? "var(--fg)" : "var(--fg-2)",
        fontSize: "13px",
        fontWeight: active ? 500 : 400,
        marginBottom: "1px",
        transition: "background 0.1s",
        textDecoration: "none",
      }}
    >
      <span style={{ fontSize: "14px", opacity: 0.7 }}>{icon}</span>
      {label}
    </Link>
  );
}

"use client";

import React from "react";
import Link from "next/link";

interface Breadcrumb {
  label: string;
  href?: string;
}

interface TopbarProps {
  breadcrumbs?: Breadcrumb[];
  actions?: React.ReactNode;
}

export function Topbar({ breadcrumbs = [], actions }: TopbarProps) {
  return (
    <header
      style={{
        height: "48px",
        borderBottom: "1px solid var(--border)",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 20px",
        background: "var(--bg-1)",
        position: "sticky",
        top: 0,
        zIndex: 10,
        flexShrink: 0,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
        {breadcrumbs.map((bc, i) => (
          <React.Fragment key={i}>
            {i > 0 && (
              <span style={{ color: "var(--fg-3)", fontSize: "12px" }}>/</span>
            )}
            {bc.href ? (
              <Link
                href={bc.href}
                style={{
                  color: "var(--fg-2)",
                  fontSize: "13px",
                  textDecoration: "none",
                }}
              >
                {bc.label}
              </Link>
            ) : (
              <span style={{ color: "var(--fg)", fontSize: "13px", fontWeight: 500 }}>
                {bc.label}
              </span>
            )}
          </React.Fragment>
        ))}
      </div>
      {actions && <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>{actions}</div>}
    </header>
  );
}

