          "I'd love to help you with your outreach campaign! Let's start — what role are you targeting and which companies interest you?",
      },
      {
        role: "user",
        content: "I'm a backend engineer targeting Series B fintech companies in NYC.",
      },
      {
        role: "assistant",
        content:
          "Great! That's a very targeted approach. What's your main value proposition? Any specific tech stack you want to highlight (Go, Rust, distributed systems, etc.)?",
      },
    ],
    extracted_params: {
      role: "Backend Engineer",
      target_companies: "Series B fintech",
      location: "NYC",
    },
  });
}

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  await params;

  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      const tokens = [
        "Great ",
        "choice! ",
        "Series B ",
        "fintechs in ",
        "NYC are ",
        "actively hiring ",
        "backend engineers. ",
      ];

      for (const token of tokens) {
        controller.enqueue(
          encoder.encode(`data: ${JSON.stringify({ type: "token", content: token })}\n\n`)
        );
        await new Promise((r) => setTimeout(r, 80));
      }

      controller.enqueue(
        encoder.encode(
          `data: ${JSON.stringify({
            type: "done",
            extracted_params: {
              role: "Backend Engineer",
              target_companies: "Series B fintech",
              location: "NYC",
            },
          })}\n\n`
        )
      );
      controller.close();
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}

