                    style={{
                      fontSize: "12px",
                      color: "var(--accent)",
                      fontWeight: 500,
                    }}
                  >
                    View →
                  </Link>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </AppShell>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";

const campaignTypes = [
  { id: "b2b", label: "B2B Sales", icon: "💼", desc: "Reach out to potential customers" },
  { id: "job_outreach", label: "Job Outreach", icon: "🎯", desc: "Land your dream job" },
  { id: "investor_outreach", label: "Investor Outreach", icon: "📈", desc: "Connect with investors" },
  { id: "custom", label: "Custom", icon: "⚡", desc: "Build your own workflow" },
];

const suggestions = [
  "Outreach to VP Engineering at Series B fintechs in NYC",
  "Land a backend role at top design-tool companies",
  "Connect with seed-stage investors focused on dev tools",
  "B2B outreach to Head of Marketing at SaaS companies",
];

export default function NewCampaignPage() {
  const router = useRouter();
  const [goal, setGoal] = useState("");
  const [selectedType, setSelectedType] = useState("b2b");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem("outreach_token");
    if (!token) {
      router.replace("/auth");
    }
  }, [router]);

  const handleSubmit = async () => {
    if (!goal.trim() && !selectedType) return;
    setLoading(true);
    try {
      const res = await fetch("/api/v1/campaigns", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ type: selectedType, goal }),
      });
      const data = await res.json();
      router.push(`/campaign/${data.campaign_id}/wizard`);
    } catch {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
      handleSubmit();
    }
  };

  return (
    <div
      style={{
        height: "100vh",
        background: "var(--bg)",
        position: "relative",
        overflow: "hidden",
        display: "flex",
        flexDirection: "column",
