          position: "absolute",
          width: "600px",
          height: "600px",
          top: "-100px",
          left: "-100px",
          background: "radial-gradient(circle, #7dd3a030 0%, transparent 70%)",
          filter: "blur(80px)",
          borderRadius: "50%",
          pointerEvents: "none",
        }}
      />
      <div
        className="aurora-blob-2"
        style={{
          position: "absolute",
          width: "500px",
          height: "500px",
          bottom: "-80px",
          right: "-80px",
          background: "radial-gradient(circle, #7aa7e828 0%, transparent 70%)",
          filter: "blur(70px)",
          borderRadius: "50%",
          pointerEvents: "none",
        }}
      />

      {/* Content */}
      <div style={{ position: "relative", zIndex: 1, width: "100%", maxWidth: "680px", padding: "0 24px" }}>
        {/* Logo */}
        <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "48px", justifyContent: "center" }}>
          <div
            style={{
              width: "28px",
              height: "28px",
              background: "var(--accent)",
              borderRadius: "7px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="var(--accent-fg)" strokeWidth="2.5">
              <path d="M22 2L11 13" strokeLinecap="round" strokeLinejoin="round" />
              <path d="M22 2L15 22l-4-9-9-4 20-7z" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </div>
          <span style={{ fontSize: "16px", fontWeight: 700, color: "var(--fg)" }}>Outreach</span>
        </div>

        <h1
          style={{
            fontSize: "36px",
            fontWeight: 700,
            color: "var(--fg)",
            textAlign: "center",
            marginBottom: "12px",
            lineHeight: 1.15,
          }}
        >
          What&apos;s your outreach goal?
        </h1>
        <p
          style={{
            fontSize: "15px",
            color: "var(--fg-2)",
            textAlign: "center",
            marginBottom: "36px",
          }}
        >
          Describe what you want to achieve and we&apos;ll build the campaign for you.
        </p>

        {/* Campaign type selector */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(4, 1fr)",
            gap: "8px",
            marginBottom: "20px",
          }}
        >
          {campaignTypes.map((t) => (
            <button
              key={t.id}
              onClick={() => setSelectedType(t.id)}
              style={{
                background: selectedType === t.id ? "var(--accent-dim)" : "var(--bg-2)",
                border: `1px solid ${selectedType === t.id ? "var(--accent)66" : "var(--border)"}`,
                borderRadius: "10px",
                padding: "12px",
