              }}
            >
              <div style={{ fontSize: "20px", marginBottom: "6px" }}>{t.icon}</div>
              <div style={{ fontSize: "12px", fontWeight: 600, color: selectedType === t.id ? "var(--accent)" : "var(--fg)", marginBottom: "2px" }}>
