"use client";

import React, { useState, use } from "react";
import { useRouter } from "next/navigation";
import { AppShell } from "@/components/layout/AppShell";
import { Button } from "@/components/ui/Button";
import { Field, Input, TextArea } from "@/components/ui/Field";

const STEPS = [
  { id: "intent", label: "Intent" },
  { id: "target", label: "Target" },
  { id: "sender", label: "Sender" },
  { id: "sources", label: "Sources" },
  { id: "review", label: "Review" },
];

interface WizardPageProps {
  params: Promise<{ id: string }>;
}

export default function WizardPage({ params }: WizardPageProps) {
  const { id } = use(params);
  const router = useRouter();
  const [step, setStep] = useState(0);
  const [loading, setLoading] = useState(false);

  // Form state
  const [form, setForm] = useState({
    // Intent
    goal: "",
    campaignType: "job_outreach",
    // Target
    targetRole: "",
    targetCompanyType: "",
    targetLocation: "",
    targetIndustry: "",
    // Sender
    senderName: "",
    senderTitle: "",
    senderCompany: "",
    senderLinkedIn: "",
    // Sources
    useApollo: true,
    useLinkedIn: true,
    useGitHub: false,
    maxContacts: "50",
  });

  const update = (key: string, val: string | boolean) =>
    setForm((f) => ({ ...f, [key]: val }));

  const handleLaunch = async () => {
    setLoading(true);
    try {
      await fetch(`/api/v1/campaigns/${id}/sessions`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      router.push(`/campaign/${id}/processing`);
    } catch {
      setLoading(false);
    }
  };

  const canNext = () => {
    if (step === 0) return form.goal.trim().length > 0;
    if (step === 1) return form.targetRole.trim().length > 0;
    if (step === 2) return form.senderName.trim().length > 0;
    return true;
  };

  return (
    <AppShell
      breadcrumbs={[
        { label: "Campaigns", href: "/dashboard" },
        { label: id.slice(0, 8) + "...", href: `/campaign/${id}/dashboard` },
        { label: "Setup" },
      ]}
    >
      <div style={{ maxWidth: "720px", display: "flex", gap: "32px" }}>
        {/* Step rail */}
        <div style={{ display: "flex", flexDirection: "column", gap: "4px", paddingTop: "4px" }}>
          {STEPS.map((s, i) => {
            const done = i < step;
            const active = i === step;
            return (
              <button
                key={s.id}
                onClick={() => i <= step && setStep(i)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "10px",
                  padding: "8px 12px",
                  borderRadius: "8px",
                  background: active ? "var(--bg-3)" : "transparent",
                  border: "none",
                  cursor: i <= step ? "pointer" : "default",
                  whiteSpace: "nowrap",
                  minWidth: "120px",
                }}
              >
                <div
                  style={{
                    width: "22px",
                    height: "22px",
                    borderRadius: "50%",
                    background: done
                      ? "var(--accent)"
                      : active
                      ? "var(--accent-dim)"
                      : "var(--bg-3)",
                    border: active ? "2px solid var(--accent)" : "2px solid var(--border)",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    flexShrink: 0,
                  }}
                >
                  {done ? (
                    <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="var(--accent-fg)" strokeWidth="3">
                      <path d="M4.5 12.75l6 6 9-13.5" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  ) : (
                    <span style={{ fontSize: "10px", color: active ? "var(--accent)" : "var(--fg-3)", fontWeight: 600 }}>
                      {i + 1}
                    </span>
                  )}
                </div>
                <span
                  style={{
                    fontSize: "13px",
                    fontWeight: active ? 600 : 400,
                    color: active ? "var(--fg)" : done ? "var(--fg-1)" : "var(--fg-3)",
                  }}
                >
                  {s.label}
                </span>
              </button>
            );
          })}
        </div>

        {/* Step content */}
        <div style={{ flex: 1 }}>
          <StepContent step={step} form={form} update={update} />

          <div style={{ display: "flex", justifyContent: "space-between", marginTop: "28px" }}>
            <Button
              variant="ghost"
              onClick={() => setStep((s) => s - 1)}
              disabled={step === 0}
            >
              ← Back
            </Button>
            {step < STEPS.length - 1 ? (
              <Button
                variant="primary"
                onClick={() => setStep((s) => s + 1)}
                disabled={!canNext()}
              >
                Next →
              </Button>
            ) : (
              <Button variant="primary" loading={loading} onClick={handleLaunch}>
                🚀 Launch Campaign
              </Button>
            )}
          </div>
        </div>
      </div>
    </AppShell>
  );
}

interface StepContentProps {
  step: number;
  form: Record<string, string | boolean>;
  update: (key: string, val: string | boolean) => void;
}

function StepContent({ step, form, update }: StepContentProps) {
  const inputStyle: React.CSSProperties = { width: "100%" };

  if (step === 0) {
    return (
      <div>
        <h2 style={{ fontSize: "18px", fontWeight: 700, color: "var(--fg)", marginBottom: "6px" }}>
          Campaign Intent
        </h2>
        <p style={{ fontSize: "13px", color: "var(--fg-2)", marginBottom: "24px" }}>
          What are you trying to achieve with this campaign?
        </p>
        <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
          <Field label="Campaign Goal" required>
            <TextArea
              fullWidth
              rows={4}
              placeholder="E.g. I'm a senior backend engineer looking for opportunities at Series B fintech startups in NYC. I specialize in Go, distributed systems, and payments infrastructure."
              value={form.goal as string}
              onChange={(e) => update("goal", e.target.value)}
            />
          </Field>
          <Field label="Campaign Type">
            <select
              value={form.campaignType as string}
              onChange={(e) => update("campaignType", e.target.value)}
              style={{
                background: "var(--bg-2)",
                border: "1px solid var(--border)",
                borderRadius: "8px",
                color: "var(--fg)",
                fontSize: "13px",
                padding: "8px 12px",
                height: "36px",
                outline: "none",
                fontFamily: "var(--font-ui)",
                width: "100%",
              }}
            >
              <option value="job_outreach">Job Outreach</option>
              <option value="b2b">B2B Sales</option>
              <option value="investor_outreach">Investor Outreach</option>
              <option value="custom">Custom</option>
            </select>
          </Field>
        </div>
      </div>
    );
  }

  if (step === 1) {
    return (
      <div>
        <h2 style={{ fontSize: "18px", fontWeight: 700, color: "var(--fg)", marginBottom: "6px" }}>
          Target Audience
        </h2>
        <p style={{ fontSize: "13px", color: "var(--fg-2)", marginBottom: "24px" }}>
          Who should we reach out to?
        </p>
        <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
          <Field label="Target Role / Title" required>
            <Input
              style={inputStyle}
              placeholder="e.g. Head of Engineering, VP of Sales"
              value={form.targetRole as string}
              onChange={(e) => update("targetRole", e.target.value)}
            />
          </Field>
          <Field label="Company Type / Stage">
            <Input
              style={inputStyle}
              placeholder="e.g. Series B fintech, Enterprise SaaS"
              value={form.targetCompanyType as string}
              onChange={(e) => update("targetCompanyType", e.target.value)}
            />
          </Field>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" }}>
            <Field label="Location">
              <Input
                style={inputStyle}
                placeholder="e.g. NYC, San Francisco, Remote"
                value={form.targetLocation as string}
                onChange={(e) => update("targetLocation", e.target.value)}
              />
            </Field>
            <Field label="Industry">
              <Input
                style={inputStyle}
                placeholder="e.g. Fintech, Dev Tools"
                value={form.targetIndustry as string}
                onChange={(e) => update("targetIndustry", e.target.value)}
              />
            </Field>
          </div>
        </div>
      </div>
    );
  }

  if (step === 2) {
    return (
      <div>
        <h2 style={{ fontSize: "18px", fontWeight: 700, color: "var(--fg)", marginBottom: "6px" }}>
          Sender Info
        </h2>
        <p style={{ fontSize: "13px", color: "var(--fg-2)", marginBottom: "24px" }}>
          Your information for personalization
        </p>
        <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" }}>
            <Field label="Your Name" required>
              <Input
                style={inputStyle}
                placeholder="Alex Johnson"
                value={form.senderName as string}
                onChange={(e) => update("senderName", e.target.value)}
              />
            </Field>
            <Field label="Your Title">
              <Input
                style={inputStyle}
                placeholder="Senior Backend Engineer"
                value={form.senderTitle as string}
                onChange={(e) => update("senderTitle", e.target.value)}
              />
            </Field>
          </div>
          <Field label="Company / Background">
            <Input
              style={inputStyle}
              placeholder="e.g. Ex-Stripe, 4 years experience"
              value={form.senderCompany as string}
              onChange={(e) => update("senderCompany", e.target.value)}
            />
          </Field>
          <Field label="LinkedIn URL">
            <Input
              style={inputStyle}
              placeholder="https://linkedin.com/in/alexjohnson"
              value={form.senderLinkedIn as string}
              onChange={(e) => update("senderLinkedIn", e.target.value)}
            />
          </Field>
        </div>
      </div>
    );
  }

  if (step === 3) {
    return (
      <div>
        <h2 style={{ fontSize: "18px", fontWeight: 700, color: "var(--fg)", marginBottom: "6px" }}>
          Data Sources
        </h2>
        <p style={{ fontSize: "13px", color: "var(--fg-2)", marginBottom: "24px" }}>
          Where should we find your contacts?
        </p>
        <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
          {[
            { key: "useApollo", label: "Apollo.io", desc: "B2B contact database with 275M+ profiles" },
            { key: "useLinkedIn", label: "LinkedIn", desc: "Professional network scraping" },
            { key: "useGitHub", label: "GitHub", desc: "Find engineers via open source contributions" },
          ].map(({ key, label, desc }) => (
            <label
              key={key}
              style={{
                display: "flex",
                alignItems: "center",
                gap: "12px",
                padding: "14px 16px",
                background: form[key] ? "var(--accent-dim)" : "var(--bg-2)",
                border: `1px solid ${form[key] ? "var(--accent)44" : "var(--border)"}`,
                borderRadius: "10px",
                cursor: "pointer",
                transition: "all 0.15s",
              }}
            >
              <input
                type="checkbox"
                checked={form[key] as boolean}
                onChange={(e) => update(key, e.target.checked)}
                style={{ width: "16px", height: "16px", accentColor: "var(--accent)", cursor: "pointer" }}
              />
              <div>
                <div style={{ fontSize: "13px", fontWeight: 600, color: "var(--fg)" }}>{label}</div>
                <div style={{ fontSize: "12px", color: "var(--fg-2)", marginTop: "1px" }}>{desc}</div>
              </div>
            </label>
          ))}
          <Field label="Max Contacts" hint="We'll find up to this many matching contacts">
            <Input
              style={{ width: "120px" }}
              type="number"
              min="10"
              max="500"
              value={form.maxContacts as string}
              onChange={(e) => update("maxContacts", e.target.value)}
            />
          </Field>
        </div>
      </div>
    );
  }

  // Step 4: Review
  return (
    <div>
      <h2 style={{ fontSize: "18px", fontWeight: 700, color: "var(--fg)", marginBottom: "6px" }}>
        Review & Launch
      </h2>
      <p style={{ fontSize: "13px", color: "var(--fg-2)", marginBottom: "24px" }}>
        Review your campaign settings before launching
      </p>
      <div
        style={{
          background: "var(--bg-2)",
          border: "1px solid var(--border)",
          borderRadius: "10px",
          overflow: "hidden",
        }}
      >
        {[
          { label: "Goal", value: (form.goal as string) || "—" },
          { label: "Type", value: (form.campaignType as string).replace(/_/g, " ") },
          { label: "Target Role", value: (form.targetRole as string) || "—" },
          { label: "Location", value: (form.targetLocation as string) || "Any" },
          { label: "Max Contacts", value: form.maxContacts as string },
          {
            label: "Sources",
            value: [
              form.useApollo ? "Apollo" : null,
              form.useLinkedIn ? "LinkedIn" : null,
              form.useGitHub ? "GitHub" : null,
            ]
              .filter(Boolean)
              .join(", ") || "None",
          },
        ].map(({ label, value }, i, arr) => (
          <div
            key={label}
            style={{
              display: "flex",
              padding: "12px 16px",
              borderBottom: i < arr.length - 1 ? "1px solid var(--border)" : "none",
              gap: "16px",
            }}
          >
            <span style={{ fontSize: "12px", color: "var(--fg-3)", width: "120px", flexShrink: 0 }}>
              {label}
            </span>
            <span style={{ fontSize: "13px", color: "var(--fg)", fontWeight: 500 }}>{value}</span>
          </div>
        ))}
      </div>
      <div
        style={{
          marginTop: "16px",
          padding: "12px 16px",
          background: "var(--accent-dim)",
          border: "1px solid var(--accent)33",
          borderRadius: "10px",
          fontSize: "13px",
          color: "var(--fg-1)",
        }}
      >
        🚀 Launching will start the AI research agents. This typically takes 2-5 minutes.
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";

interface ProcessingPageProps {
  params: Promise<{ id: string }>;
}

interface ProgressEvent {
  type: string;
  step?: string;
  message?: string;
  progress?: number;
  contact?: { company: string; person_name: string; title: string };
  count?: number;
  total_contacts?: number;
  total_drafts?: number;
}

const AGENT_STEPS = [
  { id: "research", label: "Contact Research", icon: "🔍", desc: "Finding matching contacts" },
  { id: "verify", label: "Email Verification", icon: "✉️", desc: "Verifying email addresses" },
  { id: "drafting", label: "Email Drafting", icon: "✍️", desc: "Generating personalized emails" },
  { id: "complete", label: "Quality Review", icon: "✅", desc: "Final review and cleanup" },
];

export default function ProcessingPage({ params }: ProcessingPageProps) {
  const { id } = use(params);
  const router = useRouter();
  const [progress, setProgress] = useState(0);
  const [currentStep, setCurrentStep] = useState("research");
  const [messages, setMessages] = useState<string[]>([]);
  const [done, setDone] = useState(false);
  const [contacts, setContacts] = useState<Array<{ company: string; person_name: string; title: string }>>([]);

  useEffect(() => {
    const evtSource = new EventSource(`/api/v1/campaigns/${id}/stream`);

    evtSource.onmessage = (e) => {
      try {
        const event: ProgressEvent = JSON.parse(e.data);

        if (event.type === "progress") {
          setProgress(event.progress || 0);
          setCurrentStep(event.step || "research");
          if (event.message) {
            setMessages((m) => [...m.slice(-8), event.message!]);
          }
        } else if (event.type === "contact_found" && event.contact) {
          setContacts((c) => [...c.slice(-5), event.contact!]);
        } else if (event.type === "complete") {
          setProgress(100);
          setDone(true);
          evtSource.close();
        }
      } catch {
        // ignore parse errors
      }
    };

    evtSource.onerror = () => {
      evtSource.close();
      setDone(true);
    };

    return () => evtSource.close();
  }, [id]);

  const activeStepIndex = AGENT_STEPS.findIndex((s) => s.id === currentStep);

  return (
    <div
      style={{
        height: "100vh",
        background: "var(--bg)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        position: "relative",
        overflow: "hidden",
      }}
    >
      {/* Aurora blobs */}
      <div
        className="aurora-blob-1"
        style={{
          position: "absolute",
          width: "500px",
          height: "500px",
          top: "-50px",
          left: "-50px",
          background: "radial-gradient(circle, #7dd3a028 0%, transparent 70%)",
          filter: "blur(70px)",
          borderRadius: "50%",
          pointerEvents: "none",
        }}
      />

      <div style={{ position: "relative", zIndex: 1, width: "100%", maxWidth: "560px", padding: "0 24px" }}>
        {/* Header */}
        <div style={{ textAlign: "center", marginBottom: "40px" }}>
          {!done ? (
            <>
              <div
                style={{
                  width: "48px",
                  height: "48px",
                  margin: "0 auto 16px",
                  border: "3px solid var(--border-strong)",
                  borderTopColor: "var(--accent)",
                  borderRadius: "50%",
                  animation: "spin-slow 0.9s linear infinite",
                }}
              />
              <h1 style={{ fontSize: "22px", fontWeight: 700, color: "var(--fg)", marginBottom: "8px" }}>
                Building your campaign
              </h1>
              <p style={{ fontSize: "14px", color: "var(--fg-2)" }}>
                Our AI agents are researching contacts and crafting personalized emails
              </p>
            </>
          ) : (
            <>
              <div
                style={{
                  width: "48px",
                  height: "48px",
                  margin: "0 auto 16px",
                  background: "var(--accent-dim)",
                  borderRadius: "50%",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: "24px",
                }}
              >
                ✓
              </div>
              <h1 style={{ fontSize: "22px", fontWeight: 700, color: "var(--fg)", marginBottom: "8px" }}>
                Campaign ready!
              </h1>
              <p style={{ fontSize: "14px", color: "var(--fg-2)" }}>
                Your emails are drafted and waiting for review
              </p>
            </>
          )}
        </div>

        {/* Progress bar */}
        <div
          style={{
            height: "4px",
            background: "var(--bg-3)",
            borderRadius: "2px",
            overflow: "hidden",
            marginBottom: "32px",
          }}
        >
          <div
            style={{
              height: "100%",
              background: "var(--accent)",
              borderRadius: "2px",
              width: `${progress}%`,
              transition: "width 0.5s ease",
            }}
          />
        </div>

        {/* Agent steps */}
        <div style={{ display: "flex", flexDirection: "column", gap: "8px", marginBottom: "24px" }}>
          {AGENT_STEPS.map((s, i) => {
            const isCurrent = s.id === currentStep && !done;
            const isPast = i < activeStepIndex || done;
            return (
              <div
                key={s.id}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "14px",
                  padding: "12px 16px",
                  background: isCurrent ? "var(--bg-2)" : "transparent",
                  border: `1px solid ${isCurrent ? "var(--border-strong)" : "transparent"}`,
                  borderRadius: "10px",
                  transition: "all 0.3s",
                }}
              >
                <div style={{ fontSize: "20px", opacity: isPast || isCurrent ? 1 : 0.3 }}>
                  {isPast && !isCurrent ? "✅" : s.icon}
                </div>
                <div style={{ flex: 1 }}>
                  <div
                    style={{
                      fontSize: "13px",
                      fontWeight: isCurrent ? 600 : 500,
                      color: isCurrent ? "var(--fg)" : isPast ? "var(--fg-1)" : "var(--fg-3)",
                    }}
                  >
                    {s.label}
                  </div>
                  <div style={{ fontSize: "11px", color: "var(--fg-3)", marginTop: "2px" }}>{s.desc}</div>
                </div>
                {isCurrent && (
                  <div
                    style={{
                      width: "8px",
                      height: "8px",
                      background: "var(--accent)",
                      borderRadius: "50%",
                      animation: "pulse-dot 1.2s ease-in-out infinite",
                    }}
                  />
                )}
              </div>
            );
          })}
        </div>

        {/* Live feed */}
        {contacts.length > 0 && (
          <div
            style={{
              background: "var(--bg-2)",
              border: "1px solid var(--border)",
              borderRadius: "10px",
              padding: "12px",
              marginBottom: "16px",
            }}
          >
            <div style={{ fontSize: "11px", color: "var(--fg-3)", marginBottom: "8px", textTransform: "uppercase", letterSpacing: "0.06em" }}>
              Recent Contacts Found
            </div>
            {contacts.slice(-3).map((c, i) => (
              <div key={i} style={{ display: "flex", gap: "8px", padding: "4px 0", borderBottom: i < 2 ? "1px solid var(--border)" : "none" }}>
                <span style={{ fontSize: "12px", color: "var(--accent)", fontWeight: 500 }}>{c.company}</span>
                <span style={{ fontSize: "12px", color: "var(--fg-2)" }}>{c.person_name}</span>
                <span style={{ fontSize: "12px", color: "var(--fg-3)" }}>— {c.title}</span>
              </div>
            ))}
          </div>
        )}

        {/* Messages */}
        {messages.length > 0 && (
          <div
            style={{
              fontSize: "12px",
              color: "var(--fg-3)",
              textAlign: "center",
              marginBottom: "16px",
            }}
          >
            {messages[messages.length - 1]}
          </div>
        )}

        {/* Actions */}
        <div style={{ display: "flex", flexDirection: "column", gap: "8px", alignItems: "center" }}>
          {done && (
            <Button
              variant="primary"
              size="lg"
              onClick={() => router.push(`/campaign/${id}/dashboard`)}
              style={{ width: "100%", justifyContent: "center" }}
            >
              View Campaign →
            </Button>
          )}
          <button
            onClick={() => router.push(`/campaign/${id}/dashboard`)}
            style={{
              background: "none",
              border: "none",
              color: "var(--fg-3)",
              fontSize: "12px",
              cursor: "pointer",
              fontFamily: "var(--font-ui)",
            }}
          >
            Skip to dashboard
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { AppShell } from "@/components/layout/AppShell";
import { Badge } from "@/components/ui/Badge";
import { Button } from "@/components/ui/Button";
import type { OutreachDraft, CampaignStats } from "@/types";

interface DashboardPageProps {
  params: Promise<{ id: string }>;
}

interface StatCardProps {
  label: string;
  value: number;
  color?: string;
}

function StatCard({ label, value, color }: StatCardProps) {
  return (
    <div
      style={{
        background: "var(--bg-2)",
        border: "1px solid var(--border)",
        borderRadius: "10px",
        padding: "16px",
        flex: 1,
      }}
    >
      <div style={{ fontSize: "24px", fontWeight: 700, color: color || "var(--fg)", marginBottom: "4px" }}>
        {value}
      </div>
      <div style={{ fontSize: "11px", color: "var(--fg-3)", textTransform: "uppercase", letterSpacing: "0.06em" }}>
        {label}
      </div>
    </div>
  );
}

export default function CampaignDashboard({ params }: DashboardPageProps) {
  const { id } = use(params);
  const router = useRouter();
  const [outreaches, setOutreaches] = useState<OutreachDraft[]>([]);
  const [stats, setStats] = useState<CampaignStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState({ subject: "", body: "" });
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    const token = localStorage.getItem("outreach_token");
    if (!token) {
      router.replace("/auth");
      return;
    }

    Promise.all([
      fetch(`/api/v1/campaigns/${id}/outreach`).then((r) => r.json()),
      fetch(`/api/v1/campaigns/${id}/stats`).then((r) => r.json()),
    ]).then(([outreachData, statsData]) => {
      setOutreaches(outreachData.outreaches || []);
      setStats(statsData);
      setLoading(false);
    });
  }, [id, router]);

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  };

  const updateDraftStatus = async (outreachId: string, draft_status: "approved" | "rejected") => {
    const res = await fetch(`/api/v1/campaigns/${id}/outreach/${outreachId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ draft_status }),
    });
    const data = await res.json();
    setOutreaches((o) =>
      o.map((item) => (item.id === outreachId ? { ...item, draft_status: data.draft_status } : item))
    );
    showToast(draft_status === "approved" ? "Email approved" : "Email rejected");
  };

  const startEdit = (o: OutreachDraft) => {
    setEditingId(o.id);
    setEditForm({ subject: o.subject, body: o.body });
  };

  const saveEdit = async () => {
    if (!editingId) return;
    const res = await fetch(`/api/v1/campaigns/${id}/outreach/${editingId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(editForm),
    });
    const data = await res.json();
    setOutreaches((o) =>
      o.map((item) =>
        item.id === editingId ? { ...item, subject: data.subject || editForm.subject, body: data.body || editForm.body } : item
      )
    );
    setEditingId(null);
    showToast("Draft saved");
  };

  const sendAllApproved = async () => {
    setSending(true);
    try {
      const res = await fetch(`/api/v1/campaigns/${id}/email-jobs`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
      });
      const data = await res.json();
      showToast(data.message || "Emails queued!");
    } finally {
      setSending(false);
    }
  };

  const approvedCount = outreaches.filter((o) => o.draft_status === "approved").length;

  return (
    <AppShell
      breadcrumbs={[
        { label: "Campaigns", href: "/dashboard" },
        { label: id.slice(0, 8) + "..." },
        { label: "Dashboard" },
      ]}
      actions={
        <Button
          variant="primary"
          size="sm"
          loading={sending}
          onClick={sendAllApproved}
          disabled={approvedCount === 0}
        >
          Send All Approved ({approvedCount})
        </Button>
      }
    >
      {/* Toast */}
      {toast && (
        <div
          style={{
            position: "fixed",
            bottom: "24px",
            right: "24px",
            background: "var(--bg-3)",
            border: "1px solid var(--border-strong)",
            borderRadius: "8px",
            padding: "10px 16px",
            fontSize: "13px",
            color: "var(--fg)",
            zIndex: 100,
            animation: "fadeIn 0.2s ease",
          }}
        >
          {toast}
        </div>
      )}

      {/* Stats */}
      {stats && (
        <div style={{ display: "flex", gap: "10px", marginBottom: "24px", flexWrap: "wrap" }}>
          <StatCard label="Contacts" value={stats.total_contacts} />
          <StatCard label="Drafts" value={stats.total_drafts} />
          <StatCard label="Approved" value={stats.approved} color="var(--accent)" />
          <StatCard label="Sent" value={stats.sent} color="var(--blue)" />
          <StatCard label="Opened" value={stats.opened} color="var(--amber)" />
          <StatCard label="Replied" value={stats.replied} color="var(--teal)" />
          <StatCard label="Bounced" value={stats.bounced} color="var(--red)" />
        </div>
      )}

      {/* Table header */}
      <div style={{ marginBottom: "16px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <h2 style={{ fontSize: "15px", fontWeight: 600, color: "var(--fg)" }}>
          Email Drafts ({outreaches.length})
        </h2>
        <div style={{ display: "flex", gap: "8px", fontSize: "12px", color: "var(--fg-3)" }}>
          <span>{outreaches.filter((o) => o.draft_status === "pending").length} pending</span>
          <span>·</span>
          <span>{approvedCount} approved</span>
          <span>·</span>
          <span>{outreaches.filter((o) => o.draft_status === "rejected").length} rejected</span>
        </div>
      </div>

      {loading ? (
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "200px", color: "var(--fg-3)", fontSize: "13px" }}>
          Loading drafts...
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
          {outreaches.map((o) => (
            <div
              key={o.id}
              style={{
                background: "var(--bg-2)",
                border: "1px solid var(--border)",
                borderRadius: "10px",
                overflow: "hidden",
              }}
            >
              {/* Row header */}
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "12px",
                  padding: "12px 16px",
                  borderBottom: editingId === o.id ? "1px solid var(--border)" : "none",
                }}
              >
                {/* Contact */}
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "3px" }}>
                    <span style={{ fontSize: "13px", fontWeight: 600, color: "var(--fg)" }}>
                      {o.contact.person_name}
                    </span>
                    <span style={{ fontSize: "12px", color: "var(--fg-3)" }}>at</span>
                    <span style={{ fontSize: "13px", fontWeight: 500, color: "var(--accent)" }}>
                      {o.contact.company}
                    </span>
                    {o.contact.bounce_risk && (
                      <span
                        style={{
                          fontSize: "10px",
                          background: "#e87a7a22",
                          color: "var(--red)",
                          border: "1px solid #e87a7a33",
                          borderRadius: "4px",
                          padding: "1px 6px",
                        }}
                      >
                        bounce risk
                      </span>
                    )}
                  </div>
                  <div style={{ display: "flex", gap: "8px", alignItems: "center" }}>
                    <span style={{ fontSize: "11px", color: "var(--fg-3)" }}>{o.contact.title}</span>
                    <span style={{ fontSize: "11px", color: "var(--fg-3)" }}>·</span>
                    <span style={{ fontSize: "11px", color: "var(--fg-3)" }}>{o.contact.email}</span>
                  </div>
                </div>

                {/* Subject preview */}
                <div
                  style={{
                    flex: 2,
                    fontSize: "12px",
                    color: "var(--fg-1)",
                    overflow: "hidden",
                    textOverflow: "ellipsis",
                    whiteSpace: "nowrap",
                    maxWidth: "320px",
                  }}
                >
                  {o.subject}
                </div>

                {/* Status + actions */}
                <div style={{ display: "flex", alignItems: "center", gap: "8px", flexShrink: 0 }}>
                  <Badge label={o.draft_status} />
                  <button
                    onClick={() => (editingId === o.id ? setEditingId(null) : startEdit(o))}
                    style={{
                      background: "var(--bg-3)",
                      border: "1px solid var(--border)",
                      borderRadius: "6px",
                      color: "var(--fg-2)",
                      fontSize: "11px",
                      padding: "3px 8px",
                      cursor: "pointer",
                      fontFamily: "var(--font-ui)",
                    }}
                  >
                    {editingId === o.id ? "Close" : "Edit"}
                  </button>
                  {o.draft_status !== "approved" && (
                    <button
                      onClick={() => updateDraftStatus(o.id, "approved")}
                      style={{
                        background: "var(--accent-dim)",
                        border: "1px solid var(--accent)44",
                        borderRadius: "6px",
                        color: "var(--accent)",
                        fontSize: "11px",
                        padding: "3px 8px",
                        cursor: "pointer",
                        fontFamily: "var(--font-ui)",
                        fontWeight: 600,
                      }}
                    >
                      Approve
                    </button>
                  )}
                  {o.draft_status !== "rejected" && (
                    <button
                      onClick={() => updateDraftStatus(o.id, "rejected")}
                      style={{
                        background: "#e87a7a11",
                        border: "1px solid #e87a7a33",
                        borderRadius: "6px",
                        color: "var(--red)",
                        fontSize: "11px",
                        padding: "3px 8px",
                        cursor: "pointer",
                        fontFamily: "var(--font-ui)",
                      }}
                    >
                      Reject
                    </button>
                  )}
                </div>
              </div>

              {/* Inline edit */}
              {editingId === o.id && (
                <div style={{ padding: "16px", display: "flex", flexDirection: "column", gap: "12px" }}>
                  <div>
                    <label style={{ fontSize: "11px", color: "var(--fg-3)", textTransform: "uppercase", letterSpacing: "0.06em", display: "block", marginBottom: "4px" }}>
                      Subject
                    </label>
                    <input
                      value={editForm.subject}
                      onChange={(e) => setEditForm((f) => ({ ...f, subject: e.target.value }))}
                      style={{
                        width: "100%",
                        background: "var(--bg-3)",
                        border: "1px solid var(--border-strong)",
                        borderRadius: "8px",
                        color: "var(--fg)",
                        fontSize: "13px",
                        padding: "8px 12px",
                        outline: "none",
                        fontFamily: "var(--font-ui)",
                      }}
                    />
                  </div>
                  <div>
                    <label style={{ fontSize: "11px", color: "var(--fg-3)", textTransform: "uppercase", letterSpacing: "0.06em", display: "block", marginBottom: "4px" }}>
                      Body
                    </label>
                    <textarea
                      value={editForm.body}
                      onChange={(e) => setEditForm((f) => ({ ...f, body: e.target.value }))}
                      rows={8}
                      style={{
                        width: "100%",
                        background: "var(--bg-3)",
                        border: "1px solid var(--border-strong)",
                        borderRadius: "8px",
                        color: "var(--fg)",
                        fontSize: "13px",
                        padding: "10px 12px",
                        outline: "none",
                        resize: "vertical",
                        fontFamily: "var(--font-mono)",
                        lineHeight: 1.6,
                      }}
                    />
                  </div>
                  <div style={{ display: "flex", gap: "8px" }}>
                    <Button variant="primary" size="sm" onClick={saveEdit}>
                      Save Draft
                    </Button>
                    <Button variant="ghost" size="sm" onClick={() => setEditingId(null)}>
                      Cancel
                    </Button>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </AppShell>
  );
}

